   152→// Deferred deletable stream wrapper.
   153→struct DeferredDeletableStream : public Logger::Loggable<Logger::Id::ext_proc> {
   154→  explicit DeferredDeletableStream(ExternalProcessorStreamPtr stream,
   155→                                   ThreadLocalStreamManager& stream_manager,
   156→                                   const ExtProcFilterStats& stat,
   157→                                   const std::chrono::milliseconds& timeout)
   158→      : stream_(std::move(stream)), parent(stream_manager), stats(stat),
   159→        deferred_close_timeout(timeout) {}
   160→
   161→  void deferredClose(Envoy::Event::Dispatcher& dispatcher, uint64_t stream_id);
   162→
   163→  void closeStreamOnTimer(uint64_t stream_id);
   164→  ExternalProcessorStreamPtr stream_;
   165→  ThreadLocalStreamManager& parent;
