   171→using DeferredDeletableStreamPtr = std::unique_ptr<DeferredDeletableStream>;
   172→
   173→class ThreadLocalStreamManager : public Envoy::ThreadLocal::ThreadLocalObject {
   174→public:
   175→  // Store the ExternalProcessorStreamPtr (as a wrapper object) in the map and return the raw
   176→  // pointer of ExternalProcessorStream.
   177→  ExternalProcessorStream* store(uint64_t stream_id, ExternalProcessorStreamPtr stream,
   178→                                 const ExtProcFilterStats& stat,
   179→                                 const std::chrono::milliseconds& timeout) {
   180→    stream_manager_[stream_id] =
   181→        std::make_unique<DeferredDeletableStream>(std::move(stream), *this, stat, timeout);
   182→    return stream_manager_[stream_id]->stream_.get();
   183→  }
   184→
   185→  void erase(uint64_t stream_id) { stream_manager_.erase(stream_id); }
   186→
   187→  void deferredErase(uint64_t stream_id, Envoy::Event::Dispatcher& dispatcher) {
   188→    auto it = stream_manager_.find(stream_id);
   189→    if (it == stream_manager_.end()) {
   190→      return;
   191→    }
   192→
   193→    it->second->deferredClose(dispatcher, stream_id);
   194→  }
   195→
   196→private:
   197→  // Map of DeferredDeletableStreamPtrs with stream id as key.
   198→  absl::flat_hash_map<uint64_t, DeferredDeletableStreamPtr> stream_manager_;
   199→};
